1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two live cells that each have only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 0], [0, 1]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive when it has 2 or 3 live neighbors (survival)", () => {
15	    expect(nextGeneration([[0, 0], [0, 1], [0, 2]])).toContainEqual([0, 1]);
16	  });
17	  it("should kill a live cell when it has more than 3 live neighbors (overpopulation)", () => {
18	    expect(
19	      nextGeneration([[0, 0], [0, 1], [0, -1], [1, 0], [-1, 0]])
20	    ).not.toContainEqual([0, 0]);
21	  });
22	  it.todo("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)");
23	  it.todo("should keep a block still life unchanged");
24	  it.todo("should oscillate a blinker, including negative coordinates");
25	});
26

1	export type Cell = [number, number];
2	
3	function isNeighbor(a: Cell, b: Cell): boolean {
4	  const rowDistance = Math.abs(a[0] - b[0]);
5	  const colDistance = Math.abs(a[1] - b[1]);
6	  const isSameCell = rowDistance === 0 && colDistance === 0;
7	  const isWithinOneStep = rowDistance <= 1 && colDistance <= 1;
8	  return !isSameCell && isWithinOneStep;
9	}
10	
11	export function nextGeneration(liveCells: Cell[]): Cell[] {
12	  const countNeighbors = (cell: Cell): number =>
13	    liveCells.filter((other) => isNeighbor(other, cell)).length;
14	
15	  return liveCells.filter((cell) => {
16	    const neighbors = countNeighbors(cell);
17	    return neighbors === 2 || neighbors === 3;
18	  });
19	}
